function solve(nums, edges) {
    const N = nums.length;
    const adj = Array(N).fill(0).map(() => []);

    // 1. Build adjacency list for the full graph
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }

    let resultCount = 0;
    const numSubsets = 1 << N;

    // 2. Iterate over all non-empty subsets (masks 1 to 2^N - 1)
    for (let mask = 1; mask < numSubsets; mask++) {

        // --- Step A: Check Sum Parity and calculate size ---
        let sum = 0;
        let subsetSize = 0;

        for (let i = 0; i < N; i++) {
            if ((mask >> i) & 1) {
                sum += nums[i];
                subsetSize++;
            }
        }

        // If sum is odd, skip
        if (sum % 2 !== 0) {
            continue;
        }

        // --- Step B: Check Connectivity ---

        // Subsets of size 1 are always connected
        if (subsetSize === 1) {
            resultCount++;
            continue;
        }

        // Find the starting node (lowest index in the subset)
        let startNode = -1;
        for(let i = 0; i < N; i++) {
            if ((mask >> i) & 1) {
                startNode = i;
                break;
            }
        }

        // BFS implementation
        const queue = [startNode];
        const visited = new Array(N).fill(false);
        visited[startNode] = true;
        let reachableCount = 1;

        let head = 0;
        while (head < queue.length) {
            const u = queue[head++];

            // Check neighbors in the original graph
            for (const v of adj[u]) {
                // Check if v is in the current subset (mask) AND not visited
                if (((mask >> v) & 1) && !visited[v]) {
                    visited[v] = true;
                    queue.push(v);
                    reachableCount++;
                }
            }
        }

        // If reachable count equals subset size, the induced subgraph is connected
        if (reachableCount === subsetSize) {
            resultCount++;
        }
    }

    return resultCount;
}

