fn solve(nums: Vec<i64>, edges: Vec<Vec<i64>>) -> i64 {
    let n = nums.len();

    // 1. Build adjacency list
    let mut adj: Vec<Vec<usize>> = vec![vec![]; n];
    for edge in edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        adj[u].push(v);
        adj[v].push(u);
    }

    let mut result_count: i64 = 0;
    let num_subsets = 1 << n;

    // 2. Iterate over all non-empty subsets (masks 1 to 2^N - 1)
    for mask in 1..num_subsets {

        // --- Step A: Check Sum Parity and calculate size ---
        let mut sum: i64 = 0;
        let mut subset_size: usize = 0;

        for i in 0..n {
            if (mask >> i) & 1 == 1 {
                // nums[i] is 0 or 1, so addition works fine for parity check
                sum += nums[i];
                subset_size += 1;
            }
        }

        // If sum is odd, skip
        if sum % 2 != 0 {
            continue;
        }

        // --- Step B: Check Connectivity ---

        // Subsets of size 1 are always connected
        if subset_size == 1 {
            result_count += 1;
            continue;
        }

        // Find the starting node (lowest index in the subset)
        let mut start_node = 0;
        while start_node < n && ((mask >> start_node) & 1) == 0 {
            start_node += 1;
        }

        // BFS implementation
        let mut queue: Vec<usize> = vec![start_node];
        let mut visited: Vec<bool> = vec![false; n];
        visited[start_node] = true;
        let mut reachable_count: usize = 1;

        let mut head = 0;
        while head < queue.len() {
            let u = queue[head];
            head += 1;

            // Check neighbors in the original graph
            for &v in adj[u].iter() {
                // Check if v is in the current subset (mask) AND not visited
                if ((mask >> v) & 1 == 1) && !visited[v] {
                    visited[v] = true;
                    queue.push(v);
                    reachable_count += 1;
                }
            }
        }

        // If reachable count equals subset size, the induced subgraph is connected
        if reachable_count == subset_size {
            result_count += 1;
        }
    }

    result_count
}

