function solve(nums, edges) {
    const N = nums.length;
    const adj = Array(N).fill(0).map(() => []);

    // 1. Build adjacency list
    for (const [u, v] of edges) {
        adj[u].push(v);
        adj[v].push(u);
    }

    let resultCount = 0;

    // 2. Iterate over all non-empty subsets (masks 1 to 2^N - 1)
    const numSubsets = 1 << N;

    for (let mask = 1; mask < numSubsets; mask++) {

        // --- Step A: Check Sum Parity ---
        let sum = 0;
        let subsetSize = 0;

        for (let i = 0; i < N; i++) {
            if ((mask >> i) & 1) {
                sum += nums[i];
                subsetSize++;
            }
        }

        // If sum is odd, skip
        if (sum % 2 !== 0) {
            continue;
        }

        // --- Step B: Check Connectivity ---

        // If size is 1, it's connected.
        if (subsetSize === 1) {
            resultCount++;
            continue;
        }

        // Find the starting node (any node in the set works, let's pick the lowest index)
        let startNode = -1;
        for(let i = 0; i < N; i++) {
            if ((mask >> i) & 1) {
                startNode = i;
                break;
            }
        }

        // BFS setup
        const queue = [startNode];
        // Visited array/set, only track nodes belonging to the current mask
        const visited = new Array(N).fill(false);
        visited[startNode] = true;
        let reachableCount = 1;

        let head = 0;
        while (head < queue.length) {
            const u = queue[head++];

            // Check neighbors
            for (const v of adj[u]) {
                // 1. Is v in the subset S (mask)?
                // 2. Has v not been visited yet?
                if (((mask >> v) & 1) && !visited[v]) {
                    visited[v] = true;
                    queue.push(v);
                    reachableCount++;
                }
            }
        }

        // Check if all nodes in the subset were reached
        if (reachableCount === subsetSize) {
            resultCount++;
        }
    }

    return resultCount;
}
```

